module freq_divbyeven #(
    parameter NUM_DIV = 6
) (
    input clk,
    input rst_n,
    output reg clk_div
);

    reg [3:0] cnt;
    reg clk_div_reg;
    assign clk_div = clk_div_reg;
    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            cnt <= 4'd0;
            clk_div_reg <= 1'b0;
        end
        else begin
            if(cnt < NUM_DIV/2 - 1) begin
                cnt <= cnt + 1;
                clk_div_reg <= clk_div_reg;
            end
            else begin
                cnt <= 4'd0;
                clk_div_reg <= ~clk_div_reg;
            end
        end
    end

endmodule
